/**
 * @fileoverview KaTeX lazy-loading and DOM math rendering for Markdown previews.
 * @module module/MarkdownEditor/katexMath
 */

export const KATEX_CDN_VERSION = '0.16.22';

/** @type {Promise<object> | null} */
let _katexPromise = null;

/**
 * Lazily load KaTeX from CDN and return the katex global.
 * @param {{ cdnBase?: string, version?: string }} [options]
 * @returns {Promise<object>}
 */
export function loadKaTeX(options = {}) {
    if (_katexPromise) return _katexPromise;

    const version = options.version || KATEX_CDN_VERSION;
    const cdnBase = (options.cdnBase || 'https://cdn.jsdelivr.net/npm/katex').replace(/\/$/, '');

    _katexPromise = new Promise((resolve, reject) => {
        if (typeof window !== 'undefined' && window.katex) {
            resolve(window.katex);
            return;
        }

        if (typeof document === 'undefined') {
            reject(new Error('KaTeX requires a DOM'));
            return;
        }

        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = `${cdnBase}@${version}/dist/katex.min.css`;
        document.head.appendChild(link);

        const script = document.createElement('script');
        script.src = `${cdnBase}@${version}/dist/katex.min.js`;
        script.onload = () => resolve(window.katex);
        script.onerror = () => reject(new Error('Failed to load KaTeX'));
        document.head.appendChild(script);
    });

    return _katexPromise;
}

/**
 * Render all `.math-inline` and `.math-block` elements inside a container using KaTeX.
 *
 * @param {ParentNode | null | undefined} container
 * @param {{ throwOnError?: boolean, displayMode?: boolean, katex?: object }} [options]
 * @returns {Promise<void>}
 */
export async function renderMathInElement(container, options = {}) {
    if (!container) return;

    const els = container.querySelectorAll('.math-inline, .math-block');
    if (!els.length) return;

    const throwOnError = options.throwOnError ?? false;
    const katex = options.katex || await loadKaTeX(options);

    els.forEach((el) => {
        const expr = el.getAttribute('data-math') || el.textContent || '';
        const displayMode = options.displayMode ?? el.classList.contains('math-block');
        try {
            katex.render(expr, el, { displayMode, throwOnError });
        } catch {
            /* keep raw text */
        }
    });
}

/** @deprecated Use {@link renderMathInElement} */
export function renderMathInPreview(container, options) {
    void renderMathInElement(container, options);
}
